const body = ($('Webhook').first().json.body) || {};
const types = ['cfo','certificado_habitabilidad','certificado_estructural','certificado_instalacion_electrica','certificado_instalacion_termica','informe_idoneidad','otros'];
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
if (!body.certificate_type || !types.includes(body.certificate_type)) return [{ json: { valid:false, error:'certificate_type debe ser ' + types.join('|') } }];
return [{ json: { valid:true, project_id: body.project_id, certificate_type: body.certificate_type, signer_name: body.signer_name || 'Damian Martinez', collegiate_no: body.collegiate_no || 'COAATM-XXXXX', scope: (body.scope || '').toString().slice(0, 5000), notes: (body.notes || '').toString().slice(0, 1000) } }];

const tpl = $input.first().json;
const projectRow = $('Load Project + Client').first().json.data || {};
const input = $('Validate').first().json;
const today = new Date().toLocaleDateString('es-ES', { day:'2-digit', month:'long', year:'numeric' });
const location = `${projectRow.location_address || ''}, ${projectRow.location_city || ''} (${projectRow.location_province || ''})`;
const vars = {
  project_name: projectRow.project_name || '',
  location_city: projectRow.location_city || '',
  location: location,
  property_area_m2: projectRow.property_area_m2 || '___',
  today: today,
  client_name: projectRow.client_name || '',
  signer_name: input.signer_name,
  collegiate_no: input.collegiate_no,
  scope: input.scope || '(detallar)'
};
const render = s => (s || '').replace(/\{(\w+)\}/g, (m, k) => vars[k] !== undefined ? String(vars[k]) : m);
let title, body;
if (tpl && tpl.title_template) {
  title = render(tpl.title_template);
  body  = render(tpl.body_template);
} else {
  title = 'Certificado tecnico — ' + vars.project_name;
  body  = 'Plantilla no encontrada para tipo ' + input.certificate_type;
}
return [{ json: { title, body, project_id: input.project_id, project_name: vars.project_name, certificate_type: input.certificate_type, signer_name: input.signer_name, collegiate_no: input.collegiate_no } }];

